class Solution:
    def canJump(self, nums: list[int]) -> bool:
        n = len(nums)

        if n <= 1:
            return True

        last_good_pos = n - 1
        for i in range(n - 1, -1, -1):
            if i + nums[i] >= last_good_pos:
                last_good_pos = i

        return last_good_pos == 0
